import { useEffect, useMemo, useState } from "react";
import { cn } from "../lib/utils";

export default function SideNav({ sections }) {
  const [active, setActive] = useState(sections[0]?.id ?? null);

  const ids = useMemo(() => sections.map((s) => s.id), [sections]);

  useEffect(() => {
    const elements = ids
      .map((id) => document.getElementById(id))
      .filter((el) => Boolean(el));

    if (elements.length === 0) return;

    const handleInitial = () => {
      const byTop = [...elements].sort((a, b) => Math.abs(a.getBoundingClientRect().top) - Math.abs(b.getBoundingClientRect().top))[0];
      if (byTop?.id) setActive(byTop.id);
    };

    handleInitial();

    const observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];
        if (visible?.target && visible.target.id) {
          setActive(visible.target.id);
        }
      },
      {
        root: null,
        rootMargin: "-45% 0px -45% 0px",
        threshold: [0.2, 0.4, 0.6, 0.8, 1],
      }
    );

    elements.forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, [ids]);

  const onClick = (id) => (e) => {
    e.preventDefault();
    const el = document.getElementById(id);
    if (!el) return;
    el.scrollIntoView({ behavior: "smooth", block: "start" });
    setActive(id);
  };

  return (
    <nav
      aria-label="Navegación de secciones"
      className="hidden md:flex fixed left-0 top-25 bottom-25 z-70 w-auto min-w-[200px] max-w-[240px] px-3"
    >
      <div className="h-full rounded-r-xl border-r-2 border-b-2 border-t-2 border-[#072D42]/20 bg-[#F4E9D7]/90 backdrop-blur-md p-5 flex-1 shadow-lg">
        <div className="mb-6 flex items-center justify-start">
          <div className="w-8 h-8 rounded-full bg-[#072D42] flex items-center justify-center mr-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#F4E9D7]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <span className="text-[#072D42] font-semibold text-lg">Navegación</span>
        </div>
        
        <ul className="flex flex-col gap-3">
          {sections.map((s) => {
            const isActive = active === s.id;
            return (
              <li key={s.id} className="flex">
                <a 
                  href={`#${s.id}`} 
                  onClick={onClick(s.id)} 
                  className="group block flex-1"
                >
                  <div
                    className={cn(
                      "rounded-xl p-[1px] transition-all w-full overflow-hidden",
                      isActive
                        ? "bg-gradient-to-r from-[#072D42] to-[#0a3b58] shadow-md"
                        : "bg-transparent group-hover:bg-gradient-to-r group-hover:from-[#072D42]/10 group-hover:to-[#0a3b58]/10"
                    )}
                  >
                    <div
                      className={cn(
                        "rounded-lg px-4 py-3 transition-all w-full flex items-center",
                        isActive 
                          ? "bg-[#F4E9D7] border-l-4 border-[#072D42]" 
                          : "bg-transparent group-hover:bg-[#F4E9D7]/70"
                      )}
                    >
                      <span className="relative inline-flex items-center gap-3 w-full">
                        <div className={cn(
                          "w-2 h-2 rounded-full transition-all",
                          isActive ? "bg-[#072D42]" : "bg-[#072D42]/40 group-hover:bg-[#072D42]"
                        )} />
                        <span
                          className={cn(
                            "font-medium text-sm transition-colors",
                            isActive
                              ? "text-[#072D42] font-semibold"
                              : "text-[#072D42]/70 group-hover:text-[#072D42]"
                          )}
                        >
                          {s.label}
                        </span>
                      </span>
                    </div>
                  </div>
                </a>
              </li>
            );
          })}
        </ul>
        
        <div className="mt-8 pt-4 border-t border-[#072D42]/20">
          <div className="flex items-center justify-center text-[#072D42]/60">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
            </svg>
            <span className="text-xs">Compromiso con la naturaleza</span>
          </div>
        </div>
      </div>
    </nav>
  );
}
